    pub fn parse_balance(&self, mut response: Value) -> Value {
        let mut balances: Value = self.safe_dict_k(response.clone(), "return", &[Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
})]);
        let mut timestamp: Value = self.safe_integer_k(balances.clone(), "server_time", &[]);
        let mut result: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("info".to_string(), response.clone());
                m.insert("timestamp".to_string(), timestamp.clone());
                m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
            m
        });
        let mut free: Value = self.safe_dict_k(balances.clone(), "funds", &[Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
})]);
        let mut total: Value = self.safe_dict_k(balances.clone(), "funds_incl_orders", &[Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
})]);
        let mut currencyIds: Value = object_keys(&self.extend(free.clone(), &[total.clone()]));
        {
                        let mut i: Value = Value::Int(0);
            let mut __for_first_1101: bool = true;
            while { if !__for_first_1101 { i = add(&i, &Value::Int(1)); } __for_first_1101 = false; is_less_than(&i, &get_array_length(&currencyIds)) } {
            let mut currencyId: Value = get_value(&currencyIds, &i);
            let mut currencyId: Value = get_value(&currencyIds, &i);
            let mut code: Value = self.safe_currency_code(currencyId.clone(), &[]);
            let mut account: Value = self.account();
            add_element_to_object(&mut account, &Value::Str("free".to_string()), self.safe_string(free.clone(), currencyId.clone(), &[]));
            add_element_to_object(&mut account, &Value::Str("total".to_string()), self.safe_string(total.clone(), currencyId.clone(), &[]));
            add_element_to_object(&mut result, &code, account.clone());
        }
        }
        return self.safe_balance(result.clone());

    Value::Null
}

/*
 * @method
 * @name yobit#fetchBalance
 * @see https://yobit.net/en/api
 * @description query for balance and get the amount of funds available for trading or funds locked in orders
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
 */
    pub async fn fetch_balance(&mut self, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        self.load_markets(&[]).await;
        let mut response: Value = self.private_post_get_info(&[params.clone()]).await;
        return self.parse_balance(response.clone());

    Value::Null
}

