    pub fn parse_trade(&mut self, mut trade: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        //
        // fetchTrades (public)
        //
        //      {
        //          "type":"bid",
        //          "price":0.14046179,
        //          "amount":0.001,
        //          "tid":200256901,
        //          "timestamp":1649861004
        //      }
        //
        // fetchMyTrades (private)
        //
        //      {
        //          "pair":"doge_usdt",
        //          "type":"sell",
        //          "amount":139,
        //          "rate":0.139,
        //          "order_id":"2101103631773172",
        //          "is_your_order":1,
        //          "timestamp":"1649861561"
        //      }
        //
        let mut timestamp: Value = self.safe_timestamp(trade.clone(), Value::Str("timestamp".to_string()), &[]);
        let mut side: Value = self.safe_string_k(trade.clone(), "type", &[]);
        if is_equal(&side, &Value::Str("ask".to_string())) {
            side = Value::Str("sell".to_string());
        }  else if is_equal(&side, &Value::Str("bid".to_string())) {
            side = Value::Str("buy".to_string());
        }
        let mut priceString: Value = self.safe_string2(trade.clone(), Value::Str("rate".to_string()), Value::Str("price".to_string()), &[]);
        let mut id: Value = self.safe_string2(trade.clone(), Value::Str("trade_id".to_string()), Value::Str("tid".to_string()), &[]);
        let mut order: Value = self.safe_string_k(trade.clone(), "order_id", &[]);
        let mut marketId: Value = self.safe_string_k(trade.clone(), "pair", &[]);
        let mut symbol: Value = self.safe_symbol(marketId.clone(), &[market.clone()]);
        let mut amountString: Value = self.safe_string_k(trade.clone(), "amount", &[]);
        // arguments for calculateFee (need to be numbers)
        let mut price: Value = self.parse_number(priceString.clone(), &[]);
        let mut amount: Value = self.parse_number(amountString.clone(), &[]);
        let mut type_var: Value = Value::Str("limit".to_string()); // all trades are still limit trades
        let mut fee: Value = Value::Null;
        let mut feeCostString: Value = self.safe_number_k(trade.clone(), "commission", &[]);
        if !is_equal(&feeCostString, &Value::Null) {
            let mut feeCurrencyId: Value = self.safe_string_k(trade.clone(), "commissionCurrency", &[]);
            let mut feeCurrencyCode: Value = self.safe_currency_code(feeCurrencyId.clone(), &[]);
            fee = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("cost".to_string(), feeCostString.clone());
                    m.insert("currency".to_string(), feeCurrencyCode.clone());
                m
            });
        }
        let mut isYourOrder: Value = self.safe_string_k(trade.clone(), "is_your_order", &[]);
        if !is_equal(&isYourOrder, &Value::Null) {
            if is_equal(&fee, &Value::Null) {
                let mut feeInNumbers: Value = self.calculate_fee(symbol.clone(), type_var.clone(), side.clone(), amount.clone(), price.clone(), &[Value::Str("taker".to_string())]);
                fee = Value::Map({
                    let mut m = indexmap::IndexMap::new();
                        m.insert("currency".to_string(), self.safe_string_k(feeInNumbers.clone(), "currency", &[]));
                        m.insert("cost".to_string(), self.safe_string_k(feeInNumbers.clone(), "cost", &[]));
                        m.insert("rate".to_string(), self.safe_string_k(feeInNumbers.clone(), "rate", &[]));
                    m
                });
            }
        }
        return self.safe_trade(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("id".to_string(), id.clone());
        m.insert("order".to_string(), order.clone());
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("symbol".to_string(), symbol.clone());
        m.insert("type".to_string(), type_var.clone());
        m.insert("side".to_string(), side.clone());
        m.insert("takerOrMaker".to_string(), Value::Null);
        m.insert("price".to_string(), priceString.clone());
        m.insert("amount".to_string(), amountString.clone());
        m.insert("cost".to_string(), Value::Null);
        m.insert("fee".to_string(), fee.clone());
        m.insert("info".to_string(), trade.clone());
    m
}), &[market.clone()]);

    Value::Null
}

